    cin.tie(0);
#define endl '\n'
#define f first
#define s second

typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

int main()
{
    //_
    ui n;
    int i, j;
    char l;
    string aux = "";
    cin >> n >> l;
    for (i = 0; i < n; i++)
    {
        aux += "*";
    }

    if (l == 'Q')
    {

        for (i = 0; i < n; i++)
        {
            cout << aux << '\n';
        }
    }

    else
    {
        int aux = n / 2;
        for (i = 0; i <= aux; i++)
        {
            for (j = i; j < aux; j++)
                cout << ' ';
            for (j = 0; j < (i * 2 + 1); j++)
                cout << '*';
            cout << '\n';
        }
        for (i = aux - 1; i >= 0; i--)
        {
            for (j = i; j < aux; j++)
                cout << ' ';
            for (j = 0; j < (i * 2 + 1); j++)
                cout << '*';
            cout << '\n';
        }
    }

    return 0;
}